290: 	public static findNextMatch(model: TextModel, searchParams: SearchParams, searchStart: Position, captureMatches: boolean): FindMatch | null {
291: 		const searchData = searchParams.parseSearchRequest();
292: 		if (!searchData) {
293: 			return null;
294: 		}
295: 
296: 		const searcher = new Searcher(searchData.wordSeparators, searchData.regex);
297: 
298: 		if (searchData.regex.multiline) {
299: 			return this._doFindNextMatchMultiline(model, searchStart, searcher, captureMatches);
300: 		}
301: 		return this._doFindNextMatchLineByLine(model, searchStart, searcher, captureMatches);
302: 	}
303: 
304: 	private static _doFindNextMatchMultiline(model: TextModel, searchStart: Position, searcher: Searcher, captureMatches: boolean): FindMatch | null {
305: 		const searchTextStart = new Position(searchStart.lineNumber, 1);
306: 		const deltaOffset = model.getOffsetAt(searchTextStart);
307: 		const lineCount = model.getLineCount();
308: 		// We always execute multiline search over the lines joined with \n
309: 		// This makes it that \n will match the EOL for both CRLF and LF models
310: 		// We compensate for offset errors in `_getMultilineMatchRange`
311: 		const text = model.getValueInRange(new Range(searchTextStart.lineNumber, searchTextStart.column, lineCount, model.getLineMaxColumn(lineCount)), EndOfLinePreference.LF);
312: 		const lfCounter = (model.getEOL() === '\r\n' ? new LineFeedCounter(text) : null);
313: 		searcher.reset(searchStart.column - 1);
314: 		const m = searcher.next(text);
315: 		if (m) {
316: 			return createFindMatch(
317: 				this._getMultilineMatchRange(model, deltaOffset, text, lfCounter, m.index, m[0]),
318: 				m,
319: 				captureMatches
320: 			);
321: 		}
322: 
323: 		if (searchStart.lineNumber !== 1 || searchStart.column !== 1) {
324: 			// Try again from the top
325: 			return this._doFindNextMatchMultiline(model, new Position(1, 1), searcher, captureMatches);
326: 		}
327: 
328: 		return null;
329: 	}
330: 
331: 	private static _doFindNextMatchLineByLine(model: TextModel, searchStart: Position, searcher: Searcher, captureMatches: boolean): FindMatch | null {
332: 		const lineCount = model.getLineCount();
333: 		const startLineNumber = searchStart.lineNumber;
334: 
335: 		// Look in first line
336: 		const text = model.getLineContent(startLineNumber);
337: 		const r = this._findFirstMatchInLine(searcher, text, startLineNumber, searchStart.column, captureMatches);
338: 		if (r) {
339: 			return r;
340: 		}
341: 
342: 		for (let i = 1; i <= lineCount; i++) {
343: 			const lineIndex = (startLineNumber + i - 1) % lineCount;
344: 			const text = model.getLineContent(lineIndex + 1);
345: 			const r = this._findFirstMatchInLine(searcher, text, lineIndex + 1, 1, captureMatches);
346: 			if (r) {
347: 				return r;
348: 			}
349: 		}
350: 
351: 		return null;
352: 	}
353: 
354: 	private static _findFirstMatchInLine(searcher: Searcher, text: string, lineNumber: number, fromColumn: number, captureMatches: boolean): FindMatch | null {
355: 		// Set regex to search from column
356: 		searcher.reset(fromColumn - 1);
357: 		const m: RegExpExecArray | null = searcher.next(text);
358: 		if (m) {
359: 			return createFindMatch(
360: 				new Range(lineNumber, m.index + 1, lineNumber, m.index + 1 + m[0].length),
361: 				m,
362: 				captureMatches
363: 			);
364: 		}
365: 		return null;
366: 	}
