397: 	private static _doFindPreviousMatchLineByLine(model: TextModel, searchStart: Position, searcher: Searcher, captureMatches: boolean): FindMatch | null {
398: 		const lineCount = model.getLineCount();
399: 		const startLineNumber = searchStart.lineNumber;
400: 
401: 		// Look in first line
402: 		const text = model.getLineContent(startLineNumber).substring(0, searchStart.column - 1);
403: 		const r = this._findLastMatchInLine(searcher, text, startLineNumber, captureMatches);
404: 		if (r) {
405: 			return r;
406: 		}
407: 
408: 		for (let i = 1; i <= lineCount; i++) {
409: 			const lineIndex = (lineCount + startLineNumber - i - 1) % lineCount;
410: 			const text = model.getLineContent(lineIndex + 1);
411: 			const r = this._findLastMatchInLine(searcher, text, lineIndex + 1, captureMatches);
412: 			if (r) {
413: 				return r;
414: 			}
415: 		}
416: 
417: 		return null;
418: 	}
419: 
420: 	private static _findLastMatchInLine(searcher: Searcher, text: string, lineNumber: number, captureMatches: boolean): FindMatch | null {
421: 		let bestResult: FindMatch | null = null;
422: 		let m: RegExpExecArray | null;
423: 		searcher.reset(0);
424: 		while ((m = searcher.next(text))) {
425: 			bestResult = createFindMatch(new Range(lineNumber, m.index + 1, lineNumber, m.index + 1 + m[0].length), m, captureMatches);
426: 		}
427: 		return bestResult;
428: 	}
